mapper.select:
SELECT i.id, i.grain_id, i.position_id, i.current_stock AS current_weight, g.grain_type, g.grain_grade, g.ref_purchase_price AS ref_price, i.current_stock * g.ref_purchase_price AS total_amount, s.position_name, COALESCE(in_stats.in_weight, 0) AS in_total_weight, COALESCE(in_stats.out_weight, 0) AS out_total_weight, in_stats.last_in_time, in_stats.last_out_time, i.create_time, i.update_time FROM t_inventory i INNER JOIN t_grain g ON i.grain_id = g.id INNER JOIN t_storage_position s ON i.position_id = s.id LEFT JOIN ( SELECT grain_id, position_id, SUM(CASE WHEN inbound_type = 0 THEN net_weight ELSE 0 END) AS in_weight, SUM(CASE WHEN inbound_type = 1 THEN net_weight ELSE 0 END) AS out_weight, MAX(CASE WHEN inbound_type = 0 THEN create_time END) AS last_in_time, MAX(CASE WHEN inbound_type = 1 THEN create_time END) AS last_out_time FROM t_inbound_order WHERE status = 1 GROUP BY grain_id, position_id ) in_stats ON i.grain_id = in_stats.grain_id AND i.position_id = in_stats.position_id WHERE i.status = 1
AND i.grain_id = #{grainId}
AND i.position_id = #{storagePositionId}
ORDER BY i.update_time DESC
